dashboard.definition:
{
  "title": "REST Pipeline Health",
  "description": "Example dashboard focused on the dashboard-management pipeline itself.",
  "visualizations": {
    "viz_pie": {
      "type": "splunk.pie",
      "dataSources": {
        "primary": "ds_pie"
      },
      "title": "Synthetic Object Mix",
      "options": {
        "labelDisplay": "valuesAndPercentage"
      }
    },
    "viz_markdown": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## REST-backed workflow\nDashboards are stored as XML source, pushed over Splunk REST, and can be exported back into the repo after manual edits."
      }
    }
  },
  "dataSources": {
    "ds_pie": {
      "type": "ds.search",
      "name": "Synthetic object mix",
      "options": {
        "query": "| makeresults | eval type=\"apps\", count=1 | append [| makeresults | eval type=\"users\", count=1] | append [| makeresults | eval type=\"dashboards\", count=3] | table type count"
      }
    }
  },
  "layout": {
    "type": "absolute",
    "options": {
      "display": "auto-scale",
      "width": 1440,
      "height": 900
    },
    "structure": [
      {
        "item": "viz_pie",
        "type": "block",
        "position": {
          "x": 90,
          "y": 90,
          "w": 520,
          "h": 360
        }
      },
      {
        "item": "viz_markdown",
        "type": "block",
        "position": {
          "x": 90,
          "y": 500,
          "w": 620,
          "h": 180
        }
      }
    ]
  }
}
